  changeOfficerName() {
    this.checkBoxMaster = false;

    let officer_name = this.newOfficersTargetForm
      .get("officer_name")
      .value.toLowerCase();

    this.officersAfterFiltering = this.officersAfterFiltering.map((officer) => {
      if (
        !officer.officerInformation.officer_name
          .toLowerCase()
          .includes(officer_name)
      ) {
        return { ...officer, showInGrid: false };
      } else {
        return { ...officer, showInGrid: true };
      }
    });
  }

  changeBranchCode() {
    this.newOfficersTargetForm.patchValue({ checkBox: false });
    this.checkBoxMaster = false;
    this.checkBoxResult = [];
    this.officersAfterFiltering = [];

    this.officersObjectsFromDatabase
      .filter(
        (v) =>
          v.branch_code ==
          this.newOfficersTargetForm.controls["branch_code"].value
      )
      .map((x) =>
        this.officersAfterFiltering.push({
          officerInformation: x,
          hasTargetHistory: false,
          targetHistory: { officerKey: undefined, detailsSections: [] },
          isChecked: false,
          showInGrid: true,
        })
      );
  }
  onChangeTargetGroupDate(startDate: any, endDate: any) {
    const isBetweenDates = (
      date: string,
      startDate: string,
      endDate: string
    ): boolean => {
      const dateObj = new Date(date);
      const startObj = new Date(startDate);
      const endObj = new Date(endDate);
      return dateObj >= startObj && dateObj <= endObj;
    };

    this.officersAfterFiltering = [];

    const officers = this.officersObjectsFromDatabase || [];
    const filteredOfficers = officers.filter((officer) =>
      isBetweenDates(officer.officer_emp_date, startDate, endDate)
    );

    filteredOfficers.forEach((off) => {
      this.officersAfterFiltering.push({
        officerInformation: off,
        hasTargetHistory: false,
        targetHistory: { officerKey: undefined, detailsSections: [] },
        isChecked: false,
        showInGrid: true,
      });
    });
  }

