  async addingNewTarget() {
    if (
      this.newOfficersTargetForm.controls["target_group"].value == "1" &&
      this.newOfficersTargetForm.controls["branch_code"].value == null
    ) {
      return await this.alertService.showAlertError(
        "برجاء اختيار الفرع",
        false
      );
    }
    if (this.checkBoxResult.length <= 0) {
      return await this.alertService.showAlertError(
        "برجاء اختيار المندوب",
        false
      );
    }
    if (
      this.newOfficersTargetForm.controls["target_group"].value == "3" &&
      this.newOfficersTargetForm.controls["target_group_start_date"].value ==
        null &&
      this.newOfficersTargetForm.controls["target_group_end_date"].value == null
    ) {
      return await this.alertService.showAlertError(
        "برجاء اختيار تاريخ الفترة",
        false
      );
    }
    this.isNewOfficersTargetForm = true;

    if (this.newOfficersTargetForm.valid == true) {
      if (!(await this.alertService.SaveAlert())) return;

      try {
        this.showLoader = true;
        let officersDetails = this.checkBoxResult.map(
          (x) => x.officerInformation
        );
        const request = {
          officer_key: officersDetails.map((a) => String(a.officer_key)),
          period_type: "2",
          target_start_date:
            this.newOfficersTargetForm.controls["target_start_date"].value,
          target_end_date:
            this.newOfficersTargetForm.controls["target_end_date"].value,
          target_number:
            this.newOfficersTargetForm.controls["target_number"].value,
          target_amount:
            this.newOfficersTargetForm.controls["target_amount"].value,
        };
        await this.http
          .post(this.env.API_URL + "api/Officer/InsertOfficerTarget", request)
          .toPromise();
        this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
      } catch (err) {
        console.error(err);
        await this.alertService.showAlertError(err.error, false);
      } finally {
        this.showLoader = false;
      }
    } else {
      this.ScrollingService.findInvalidControls(this.newOfficersTargetForm);
    }
  }

