  generateMonthYearDropDown(
    numberOfPrevMonths: number,
    numberOfNextMonths: number
  ): {
    name: string;
    date: string;
  }[] {
    var date1 = new Date();
    var date2 = new Date();
    let prevMonths: { name: string; date: string }[] = [];
    let nextMonths: { name: string; date: string }[] = [];
    var monthNames = [
      "يناير",
      "فبراير",
      "مارس",
      "أبريل",
      "مايو",
      "يونيو",
      "يوليو",
      "أغسطس",
      "سبتمبر",
      "أكتوبر",
      "نوفمبر",
      "ديسمبر",
    ];

    var currentMonth = date1.getMonth();

    // Generate previous months
    for (var i = numberOfPrevMonths; i > 0; i--) {
      currentMonth--;
      if (currentMonth < 0) {
        currentMonth = 11;
        date1.setFullYear(date1.getFullYear() - 1);
      }
      prevMonths.unshift({
        name: monthNames[currentMonth] + " " + date1.getFullYear(),
        date: format(
          new Date(date1.getFullYear(), currentMonth, 1),
          "yyyy-MM-dd"
        ),
      });
    }
    // Reset to the original month and year
    currentMonth = date2.getMonth();

    // Generate current month and future months
    for (var j = 0; j <= numberOfNextMonths; j++) {
      nextMonths.push({
        name: monthNames[currentMonth] + " " + date2.getFullYear(),
        date: format(
          new Date(date2.getFullYear(), currentMonth, 1),
          "yyyy-MM-dd"
        ),
      });
      currentMonth++;
      if (currentMonth > 11) {
        currentMonth = 0;
        date2.setFullYear(date2.getFullYear() + 1);
      }
    }
    return prevMonths.concat(nextMonths);
  }

  async checkOfficerTargetHistory() {
    const targetStartDateControl =
      this.newOfficersTargetForm.controls["target_start_date"].value;
    const targetEndDateControl =
      this.newOfficersTargetForm.controls["target_end_date"].value;
    const officersToShow = this.officersAfterFiltering;

    if (
      officersToShow.length === 0 ||
      targetStartDateControl === null ||
      targetEndDateControl === null
    )
      return;

    try {
      this.showLoader = true;

      const requestObject: GetOfficerTargetHistoryRequest = {
        officer_key: officersToShow.map((a) =>
          String(a.officerInformation.officer_key)
        ),
        target_start_date: targetStartDateControl,
        target_end_date: targetEndDateControl,
      };

      const targetHistoryDatabaseResponse = await this.officerServices
        .getOfficerTargetHistory(requestObject)
        .toPromise();

      this.officersAfterFiltering = officersToShow.map((officer) => {
        const matchingResponse = targetHistoryDatabaseResponse.find(
          (res) =>
            res.officerKey === Number(officer.officerInformation.officer_key)
        );

        if (matchingResponse) {
          officer.hasTargetHistory = true;
          officer.targetHistory = {
            officerKey: matchingResponse.officerKey,
            detailsSections: matchingResponse.detailsSections,
          };
        } else {
          officer.hasTargetHistory = false;
          officer.targetHistory = {
            officerKey: undefined,
            detailsSections: [],
          };
        }

        return officer;
      });

      this.showLoader = false;
    } catch (error) {
      console.log(error);
      await this.alertService.showAlertError(
        "حدث خطا في: " + error.error + "",
        false
      );
      this.showLoader = false;
    }
  }

  closingSelectedOfficerTargetModal() {
    this.officerDetailModel.isOpen = false;
  }
  async getAllOfficers() {
    try {
      this.showLoader = true;
      const allOfficers = await this.officerServices
        .getAllOfficers()
        .toPromise();

      this.officersObjectsFromDatabase = allOfficers.map((officer) => ({
        ...officer,
        officer_emp_date: this.datePipe.transform(
          officer.officer_emp_date,
          "yyyy-MM-dd"
        ),
      }));

      this.officersObjectsFromDatabase.forEach((off) => {
        this.officersAfterFiltering.push({
          officerInformation: off,
          hasTargetHistory: false,
          targetHistory: { officerKey: undefined, detailsSections: [] },
          isChecked: false,
          showInGrid: true,
        });
      });
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      this.alertService.showAlertError(
        error?.error || "خطأ في المناديب",
        false
      );
    }
  }
  convertDateToArabicMonths = (date: string): string => {
    var monthNames = [
      "يناير",
      "فبراير",
      "مارس",
      "أبريل",
      "مايو",
      "يونيو",
      "يوليو",
      "أغسطس",
      "سبتمبر",
      "أكتوبر",
      "نوفمبر",
      "ديسمبر",
    ];

    const inputDate = new Date(date);
    const month = getMonth(inputDate);
    const year = getYear(inputDate);

    return monthNames[month] + " " + String(year);
  };
